UPDATE pms_stock
SET stock = stock - #{count}
WHERE product_id = #{productId} AND stock >= #{count} AND delete_status = 0

UPDATE pms_stock
SET stock = stock + #{count}
WHERE product_id = #{productId} AND delete_status = 0

UPDATE pms_stock
SET stock = #{stock}
WHERE product_id = #{productId} AND delete_status = 0
